                            "tier": "junior",
                            "code": "// === JUNIOR EXAMPLE ===\n// TASK      - Real-world usage of Error Boundaries with react-error-boundary — common patterns you'll see in production.\n// APPROACH  - Combine Error Boundaries with react-error-boundary with related functions; handle common edge cases.\n// STRENGTHS - Practical; covers the 80% use cases encountered on the job.\n// WEAKNESSES- May need optimization for large datasets or complex queries.\n// APPROACH  - real-world usage with proper patterns\n// STRENGTHS - production-ready, handles common cases\n// WEAKNESSES- no advanced optimization\n//\nfunction ErrorFallback({ error, resetErrorBoundary }) {\n  return (\n    <div className=\"p-6 bg-red-50 border border-red-200 rounded-lg\">\n      <h2 className=\"text-red-900 font-bold mb-2\">Something went wrong</h2>\n      <pre className=\"text-red-700 text-sm bg-red-100 p-2 rounded mb-4 overflow-auto\">\n        {error.message}\n      </pre>\n      <button\n        onClick={resetErrorBoundary}\n        className=\"px-4 py-2 bg-red-600 text-white rounded hover:bg-red-700\"\n      >\n        Try again\n      </button>\n    </div>\n  );\n}\nfunction App() {\n  return (\n    <ErrorBoundary\n      FallbackComponent={ErrorFallback}\n      onError={(error, info) => {\n        // Log to error tracking service\n        console.error(\"Error:\", error);\n        console.error(\"Component Stack:\", info.componentStack);\n      }}\n    >\n      <Dashboard />\n    </ErrorBoundary>\n  );\n}\nfunction UserProfile({ userId }) {\n  return (\n    <ErrorBoundary\n      FallbackComponent={ErrorFallback}\n      resetKeys={[userId]}  // Reset when userId changes\n    >\n      <ProfileContent userId={userId} />\n    </ErrorBoundary>\n  );\n}\nfunction DeleteButton({ onDelete }) {\n  const { showBoundary } = useErrorBoundary();\n  async function handleDelete() {\n    try {\n      await onDelete();\n    } catch (error) {\n      // Propagate to nearest ErrorBoundary\n      showBoundary(error);\n    }\n  }\n  return <button onClick={handleDelete}>Delete</button>;\n}"
